INSERT INTO `ai_config` VALUES (1,'隐患分析助手','zhipu','https://open.bigmodel.cn/api/paas/v4','e2cdbdb098f741a8a869af9aac5270aa.0zwXFJ12sXLrOe5J','glm-5',2000,0.30,'你是一名专业的安全生产管理专家，具备丰富的安全法规知识。请对提供的隐患信息进行分析，重点识别：\r\n1. 是否存在违法违规情形（参考《安全生产法》《特种设备安全法》等法规）\r\n2. 风险等级评估（极其危险/高度危险/显著危险/一般危险）\r\n3. 可能导致的后果\r\n4. 整改建议\r\n\r\n请用JSON格式返回结果，包含字段：risk_level(风险等级)、violation(是否违规true/false)、violation_detail(违规描述)、consequence(可能后果)、suggestion(整改建议)、law_ref(相关法规依据)',0,'2026-03-27 09:51:51','2026-04-01 17:02:04'),(2,'longtian','deepseek','https://api.deepseek.com/v1/chat/completions','sk-fb3b2196a5f74265a61363a00e4f64d2','deepseek-chat',2000,0.30,'',0,'2026-03-29 08:42:29','2026-03-29 09:45:15'),(4,'longtian硅基流动','custom','https://api.siliconflow.cn/v1/chat/completions','sk-kthodgdcadpdjiolghputuhmrcfzyixhsuesjewlivyxcxeg','Qwen/Qwen2.5-72B-Instruct',2000,0.30,'',0,'2026-03-29 09:37:14','2026-03-29 15:05:55'),(5,'longtian','zhipu','https://open.bigmodel.cn/api/paas/v4/chat/completions','9ca2********FbEc','glm-5',2000,0.30,'你是一名专业的安全生产管理专家，具备丰富的安全法规知识。请对提供的隐患信息进行分析，重点识别：\r\n1. 该企业在山东省内，查询时先参考山东省法律法规，是否存在违法违规情形（参考《安全生产法》《特种设备安全法》等法规）\r\n2. 风险等级评估（极其危险/高度危险/显著危险/一般危险）\r\n3. 可能导致的后果\r\n4. 整改建议\r\n5. 相关法规依据\r\n\r\n请用JSON格式返回结果，包含字段：risk_level(风险等级)、violation(是否违规true/false)、violation_detail(违规描述)、consequence(可能后果)、suggestion(整改建议)、law_ref(相关法规依据)',0,'2026-03-29 09:44:14','2026-03-31 21:00:53'),(6,'智普ai','custom','https://open.bigmodel.cn/api/paas/v4/chat/completions','4dd3********pqV7','glm-5',2000,0.30,'你是一名专业的安全生产管理专家，具备丰富的安全法规知识。请对提供的隐患信息进行分析，重点识别：\r\n1. 该企业为山东省企业，查询法规时注意山东省法律法规，是否存在违法违规情形（参考《安全生产法》《特种设备安全法》等法规）\r\n2. 风险等级评估（极其危险/高度危险/显著危险/一般危险）\r\n3. 可能导致的后果\r\n4. 整改建议\r\n5. 相关法规依据\r\n\r\n请用JSON格式返回结果，包含字段：risk_level(风险等级)、violation(是否违规true/false)、violation_detail(违规描述)、consequence(可能后果)、suggestion(整改建议)、law_ref(相关法规依据)',0,'2026-03-29 10:10:17','2026-04-01 16:57:50'),(7,'longtian硅基流动','siliconflow','https://api.siliconflow.cn/v1/chat/completions','admin123','Qwen2.5-72B-Instruct',2000,0.30,'你是一名专业的安全生产管理专家，具备丰富的安全法规知识。请对提供的隐患信息进行分析，重点识别：\r\n1. 该企业为山东省内精细化工企业，是否存在违法违规情形（参考《安全生产法》《特种设备安全法》等法规）\r\n2. 风险等级评估（极其危险/高度危险/显著危险/一般危险）\r\n3. 可能导致的后果\r\n4. 整改建议\r\n5. 相关法规依据\r\n\r\n请用JSON格式返回结果，包含字段：risk_level(风险等级)、violation(是否违规true/false)、violation_detail(违规描述)、consequence(可能后果)、suggestion(整改建议)、law_ref(相关法规依据)',0,'2026-03-30 09:49:10','2026-03-30 09:49:17'),(8,'千问龙田','qianwen','https://dashscope.aliyuncs.com/compatible-mode/v1','sk-7********fa53','qwen-max',2000,0.30,'化工类安全专家',0,'2026-04-02 11:23:30','2026-04-02 16:13:57');
