INSERT INTO `exam_questions` VALUES (1,'消防安全',1,3,'火灾发生的三个要素是什么？',1,'可燃物+助燃物+着火源','可燃物+水+氧气','热量+可燃物+水','氧气+热量+水','A','火灾三要素：可燃物、助燃物（氧气）、着火源，缺一不可。',0,'2026-03-27 09:50:48','2026-03-27 09:50:48'),(2,'电气安全',2,3,'低压电气设备安全电压的上限值为多少伏？',1,'36V','48V','24V','12V','A','国标规定安全电压上限为36V（特殊场所12V或24V）。',0,'2026-03-27 09:50:48','2026-03-27 09:50:48'),(3,'安全管理',2,3,'根据《安全生产法》，生产经营单位的安全生产第一责任人是？',1,'安全总监','主要负责人','安全管理员','工会主席','B','《安全生产法》明确主要负责人（法定代表人/实际控制人）为安全生产第一责任人。',0,'2026-03-27 09:50:48','2026-03-27 09:50:48'),(4,'特种设备',2,3,'特种设备年检的主要目的是什么？',1,'提高生产效率','检查设备安全状况防止事故','降低设备成本','了解设备技术参数','B','年检是对特种设备安全性能的定期检验，确保设备安全运行。',0,'2026-03-27 09:50:48','2026-03-27 09:50:48'),(5,'应急处置',1,3,'发现有人触电时，第一步应该做什么？',1,'立即拨打120','直接用手拉触电者','立即切断电源或用绝缘物使触电者脱离电源','向周围大声呼救','C','触电急救第一步：立即断电或用绝缘物使其脱离电源，严禁直接接触。',0,'2026-03-27 09:50:48','2026-03-27 09:50:48'),(6,'消防安全',2,3,'以下哪种灭火器不能用于扑救电气火灾？',1,'二氧化碳灭火器','干粉灭火器','泡沫灭火器','清水灭火器（不含导电成分）','C','泡沫灭火器含水导电，不能用于带电设备灭火。',0,'2026-03-27 09:50:48','2026-03-27 09:50:48'),(7,'安全管理',1,3,'以下关于安全帽佩戴正确的是？',1,'系好下颌带','反戴安全帽更舒适','安全帽越紧越安全','帽衬可以取出使用','A','安全帽必须系好下颌带，帽衬完整，正确佩戴。',0,'2026-03-27 09:50:48','2026-03-27 09:50:48'),(8,'应急处置',3,5,'发生化学品泄漏时，疏散方向应该选择？',1,'顺风方向','侧风方向','逆风方向','就近方向','C','化学品泄漏疏散应向逆风（上风口）方向撤离，避免吸入有毒气体。',0,'2026-03-27 09:50:48','2026-03-27 09:50:48'),(9,'职业健康',2,3,'以下哪项属于职业病防治的\"三级预防\"第一级？',1,'早期治疗','定期体检','消除危害因素','康复治疗','C','一级预防为病因预防：消除或控制危害因素，从根本上预防职业病。',0,'2026-03-27 09:50:48','2026-03-27 09:50:48'),(10,'安全管理',1,5,'进入受限空间前必须进行的检测包括哪些（多选）？',2,'可燃气体检测','氧气含量检测','有毒有害气体检测','温度检测','ABC','进入受限空间前必须检测：可燃气体、氧含量、有毒有害气体。',0,'2026-03-27 09:50:48','2026-03-27 09:50:48'),(11,'消防安全',1,2,'以下说法正确的是（判断题）：在任何情况下发现火情都应立即拨打119。',3,'','','','','T','发现火情第一时间拨打119报警，同时根据实际情况决定是否自救。',0,'2026-03-27 09:50:48','2026-03-27 09:50:48'),(12,'电气安全',1,2,'漏电保护器只能保护人身安全，不能防止电气火灾。（判断题）',3,'','','','','F','漏电保护器既能保护人身安全，也能在一定程度上防止漏电引起的电气火灾。',0,'2026-03-27 09:50:48','2026-03-27 09:50:48');
