INSERT INTO `three_level_templates` VALUES (1,'factory','厂级安全教育（一级）',24.00,'安全生产方针政策与法律法规、本单位安全生产规章制度和劳动纪律、从业人员安全生产权利和义务、事故应急救援/应急预案演练及防范措施、有关事故案例',NULL,1,1,'2026-05-12 13:31:45','2026-05-12 13:31:45'),(2,'workshop','车间级安全教育（二级）',24.00,'工作环境及危险因素、所从事工种可能遭受的职业伤害和伤亡事故、所从事工种的安全职责/操作技能及强制性标准、自救互救/急救方法/疏散和现场紧急情况的处理、安全设备设施/个人防护用品的使用和维护、本车间安全生产状况及规章制度、预防事故和职业危害的措施及应注意的安全事项、有关事故案例',NULL,1,2,'2026-05-12 13:31:45','2026-05-12 13:31:45'),(3,'team','班组级安全教育（三级）',24.00,'岗位安全操作规程、岗位之间工作衔接配合的安全与职业卫生事项、岗位典型事故案例、劳动防护用品（用具）的性能及正确使用方法、岗位隐患排查方法与要点',NULL,1,3,'2026-05-12 13:31:45','2026-05-12 13:31:45');
